#include <stdio.h>
#include <stdlib.h>
#define MAX 200

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, K, D, x, y;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        scanf("%d", &K);
        int days[K], cost[K];
        for (int j = 0; j < K; j++) {
            scanf("%d", &days[j]);
        }
        for (int j = 0; j < K; j++) {
            scanf("%d", &cost[j]);
        }
        scanf("%d", &D);
        int dependencies[D][2];
        for (int j = 0; j < D; j++) {
            scanf("%d %d", &x, &y);
            dependencies[j][0] = x - 1;
            dependencies[j][1] = y - 1;
        }
        int finish_time[K];
        for (int j = 0; j < K; j++) {
            finish_time[j] = days[j];
        }
        for (int j = 0; j < D; j++) {
            finish_time[dependencies[j][1]] = finish_time[dependencies[j][0]] + days[dependencies[j][1]];
        }
        int total_cost = 0;
        for (int j = 0; j < K; j++) {
            total_cost += finish_time[j] * cost[j];
        }
        printf("Case %d: %d\n", i + 1, total_cost);
    }
    return 0;
}

