import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int i = 0; i < T; i++) {
            int K = scanner.nextInt();
            int[] days = new int[K];
            int[] cost = new int[K];
            for (int j = 0; j < K; j++) {
                days[j] = scanner.nextInt();
            }
            for (int j = 0; j < K; j++) {
                cost[j] = scanner.nextInt();
            }
            int D = scanner.nextInt();
            int[][] dependencies = new int[D][2];
            for (int j = 0; j < D; j++) {
                dependencies[j][0] = scanner.nextInt() - 1;
                dependencies[j][1] = scanner.nextInt() - 1;
            }
            int[] finish_time = new int[K];
            for (int j = 0; j < K; j++) {
                finish_time[j] = days[j];
            }
            for (int j = 0; j < D; j++) {
                finish_time[dependencies[j][1]] = finish_time[dependencies[j][0]] + days[dependencies[j][1]];
            }
            int total_cost = 0;
            for (int j = 0; j < K; j++) {
                total_cost += finish_time[j] * cost[j];
            }
            System.out.println("Case " + (i + 1) + ": " + total_cost);
        }
    }
}

