const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

for (let i = 0; i < parseInt(readline()); i++) {
    const K = parseInt(readline());
    const days = readline().split(' ').map(Number);
    const cost = readline().split(' ').map(Number);
    const D = parseInt(readline());
    const dependencies = [];
    for (let j = 0; j < D; j++) {
        const [x, y] = readline().split(' ').map(Number);
        dependencies.push([x - 1, y - 1]);
    }
    const finish_time = days.slice();
    for (const [x, y] of dependencies) {
        finish_time[y] = finish_time[x] + days[y];
    }
    const total_cost = finish_time.reduce((acc, f, i) => acc + f * cost[i], 0);
    console.log(`Case ${i + 1}: ${total_cost}`);
}
